@@ -447,25 +447,32 @@ export default class MutterButterExtension extends Extension {
         if (!WindowStateHandler.isManaged(metaWindow))
             return;

-        // Wait for actor to be available, then for first-frame.
-        // Use timeout (not idle) to avoid spin-looping if actor is delayed.
         let retries = 0;
         const maxRetries = 20;
         const checkActor = () => {
             const actor = metaWindow.get_compositor_private();
             if (actor) {
+                let handled = false;
                 actor.connect('first-frame', () => {
+                    if (handled) return;
+                    handled = true;
                     this._onWindowReady(metaWindow);
                 });
+                // Fallback if first-frame never fires (e.g., headless mode)
+                GLib.timeout_add(GLib.PRIORITY_DEFAULT, 500, () => {
+                    if (handled) return GLib.SOURCE_REMOVE;
+                    handled = true;
+                    this._onWindowReady(metaWindow);
+                    return GLib.SOURCE_REMOVE;
+                });
                 return GLib.SOURCE_REMOVE;
             }
             retries++;
             if (retries >= maxRetries)
-                return GLib.SOURCE_REMOVE; // Give up
+                return GLib.SOURCE_REMOVE;
             return GLib.SOURCE_CONTINUE;
         };

-        // Try immediately, then poll with timeout
         if (checkActor() === GLib.SOURCE_CONTINUE)
             GLib.timeout_add(GLib.PRIORITY_DEFAULT, 50, checkActor);
     }
